methods.lobby_open_door_check:
def lobby_open_door_check(self, check_time=3):
    open_door = False
    open_loop = 0
    while not open_door and open_loop < check_time:
        if self.wait_door_open(time_out=1.14):
            open_door = True
        else:
            self.sleep(0.1)
            self.send_key('interact', down_time=0.1)
            self.sleep(0.2)
            open_loop += 1
    return open_door
